<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>2048 Game</title>
    <style>
        body {
            background-color: #1a1a2e;
            color: #fff;
            font-family: 'Courier New', monospace;
            margin: 0;
            padding: 20px;
        }

        .container {
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            background-color: #2c3e50;
            border-radius: 10px;
            box-shadow: 0 4px 8px rgba(0,0,0,0.5);
        }

        .game-area {
            width: 400px;
            height: 400px;
            background-color: #1a1a2e;
            border-radius: 10px;
            display: flex;
            justify-content: center;
            align-items: center;
            margin-bottom: 20px;
            box-shadow: 0 4px 8px rgba(0,0,0,0.5);
        }

        #score {
            font-size: 24px;
            color: #e74c3c;
            text-align: right;
        }

        button {
            background-color: #27ae60;
            color: white;
            border: none;
            padding: 10px 20px;
            font-size: 16px;
            cursor: pointer;
            margin-top: 15px;
        }
    </style>
</head>
<body>
    <div class="container">
        <div class="game-area">
            <h1>2048 Game</h1>
            <div id="score">Score: 0</div>
            <button onclick="resetGame()">Reset Game</button>
        </div>
    </div>

    <script>
        window.game = {
            size: 4,
            reset(): {
                // Clear board and set initial state
                this.setBoard([]);
                this.score = 0;
            },
            move(direction): {
                const board = this.board();
                let changed = false;

                switch (direction) {
                    case 'left':
                        this.moveLeft(board);
                        break;
                    case 'right':
                        this.moveRight(board);
                        break;
                    case 'up':
                        this.moveUp(board);
                        break;
                    case 'down':
                        this.moveDown(board);
                        break;
                }

                return changed;
            },
            moveLeft(board): {
                // Move all tiles left
                const newBoard = board.map(row => row.slice(-1, -2).concat(row.slice(0, -1)));
                if (newBoard.length > 0) {
                    this.setBoard(newBoard);
                    this.score += board.reduce((sum, val) => sum + val * 2, 0); // Score adds double for each tile
                    changed = true;
                }
            },
            moveRight(board): {
                const newBoard = board.map(row => row.slice(-1, -2).concat(row.slice(0, -1)));
                if (newBoard.length > 0) {
                    this.setBoard(newBoard);
                    this.score += board.reduce((sum, val) => sum + val * 2, 0); // Score adds double for each tile
                    changed = true;
                }
            },
            moveUp(board): {
                const newBoard = board.map(row => row.slice(-1).concat(row.slice(0, -1)));
                if (newBoard.length > 0) {
                    this.setBoard(newBoard);
                    this.score += board.reduce((sum, val) => sum + val * 2, 0); // Score adds double for each tile
                    changed = true;
                }
            },
            moveDown(board): {
                const newBoard = board.map(row => row.slice(-1).concat(row.slice(0, -1)));
                if (newBoard.length > 0) {
                    this.setBoard(newBoard);
                    this.score += board.reduce((sum, val) => sum + val * 2, 0); // Score adds double for each tile
                    changed = true;
                }
            },
            setBoard(arr): {
                this.board = arr;
            },
            score(): number {
                return this.score;
            }
        };
    </script>
</body>
</html>
